/* === Hide the NavBar === */
.Navbar {
visibility:hidden;
display: none;
}
/* === Hide the NavBar === */

* {margin:0px; padding:0px;}
body {background: #DEB968 url(http://www.webpagedesign.ws/aspire/body-bg.jpg) center top; text-align:center; font-size:12px; color:#240f02; font-family: Verdana, Arial, Helvetica, sans-serif;}

img {border: medium none;}
blockquote {padding: 5px 20px; text-align: left; color:#602600}
blockquote blockquote {padding: 2px 10px; text-align: left; color:#602600; font-style:italic;}
a {text-decoration:none; color:#c97e00; border: 0px;}
a:hover {text-decoration:underline; border: 0px;}
a.u {text-decoration:underline; border: 0px;}
a.u:hover {text-decoration:none; border: 0px;}
a.n, a.n:hover {text-decoration:none; border: 0px;}
a:focus, a:active {outline: none;}

p {padding:7px 0;  line-height: 17px;}
.border {border:1px solid red;}
h1, h2, h3, h4 { font-family: "Trebuchet MS";}
hr {border-left:0px solid #abb0b5; border-right:0px solid #abb0b5; border-top:1px dotted #abb0b5; border-bottom:0px solid #abb0b5; height: 1px;}

input {font-family: 'Verdana'; color: #240f02; font-size: 11px;}
textarea {font-family: 'Verdana'; color: #240f02; font-size: 11px;}
select {font-family: 'Verdana'; color: #240f02; font-size: 11px;}

.left-bg {position:absolute; left:0px; top:0px; width:50%; height:517px; margin-left:-495px; background: url(http://www.webpagedesign.ws/aspire/top-left-bg-repeat.jpg) right top repeat-x;}
.script {position:absolute; right:0px; top:104px; width:100%; height:413px; background: url(http://www.webpagedesign.ws/aspire/left-bg.jpg) right top no-repeat;}
.right-bg {position:absolute; right:0px; top:0px; width:50%; height:223px; background: url(http://www.webpagedesign.ws/aspire/top-right-bg-repeat.jpg) 40px 0px repeat-x;}
#head {position:relative; width:990px; height:250px; margin:0 auto; text-align:left; background: url(http://www.webpagedesign.ws/aspire/top-right-bg-repeat.jpg) 90px 0px repeat-x;}
.crack {position:absolute; left:0px; top:0px; width:990px; height:51px; background: url(http://www.webpagedesign.ws/aspire/crack.jpg) 627px 0px no-repeat;}
.header {width:627px; height:250px; background: url(http://www.webpagedesign.ws/aspire/header-bg.jpg) no-repeat;}
	.logo {position:absolute; left:0px; top:120px; width:627px;}
	.logo h1 {font: bold 27px/120% Georgia; color:#602600; padding:0 0 10px 20px; margin-right:16px;}
	.logo h1 a, .logo h1 a:hover {color:#602600; text-decoration:none;}
	.logo a b {}
	.shadow-right {position:absolute; left:627px; top:115px; width:102px; height:380px; background: url(http://www.webpagedesign.ws/aspire/right-bg.jpg) no-repeat;}
	#menu {position:absolute; left:100px; top:80px;}
	#menu ul {list-style:none;}
	#menu ul li {display:block; float:left; padding:0 17px;}
	* html #menu ul li {display:inline;}
	#menu ul li a {color:#97712c;}
	.searchbox {position:absolute; left:640px; top:100px; width:176px; font-size:11px; color:#97712c;}
	#searchform .label {display:block; padding:0px 0px 2px 5px;}
		.search {width:135px; height:20px; background: url(http://www.webpagedesign.ws/aspire/search-input.gif) left top no-repeat; float:left;}
	#searchform input {border:none; background:transparent url(http://www.webpagedesign.ws/aspire/go-button.gif) left top no-repeat; font-weight: bold; color:#ceb978; width:30px; height:20px; float:right;}
	#searchform .search #s {border:none; background:transparent; color:#ceb978; width:125px; height:auto !important; margin:3px 0 0 4px; float:left;}

#content {position:relative; width:990px; margin:0 auto; text-align:left;}
#main {position:relative; float:left; width:627px;}
	.content-wrapper {position:relative; width:627px; overflow=hidden;} 
	.content {position:relative; width:627px; background: url(http://www.webpagedesign.ws/aspire/content-bg.jpg);} 
	.cont-r {position:relative; background: url(http://www.webpagedesign.ws/aspire/border.gif) right top repeat-y;}
	.cont-l {position:relative; background: url(http://www.webpagedesign.ws/aspire/border.gif) left top repeat-y;}
	.cont-bottom {position:relative; background: url(http://www.webpagedesign.ws/aspire/content-bottom-bg.jpg) left bottom no-repeat; top:0px; bottom:0px; height:40px; margin-top:-40px;}
	.grad-hack {position:relative; background: url(http://www.webpagedesign.ws/aspire/header-bg.jpg) 0px -170px no-repeat; width:627px; overflow:hidden; margin-top:-80px; padding-bottom:20px;}
	* html .grad-hack {position:relative;min-height:200px;}

	.begin {background: url(http://www.webpagedesign.ws/aspire/begin.gif) 10px 0px no-repeat; position:absolute; top:10px; left:0px; width:100%; height:40px; z-index:10;}

	.content h1 {font: 20px "Trebuchet MS"; color:#602600; letter-spacing:-1px; padding-top:10px;}
	.content h2 {font:bold 18px "Trebuchet MS"; color:#602600; padding:10px 0px 2px 20px;}
	.content h3 {font:bold 16px "Trebuchet MS"; color:#602600; padding:10px 0px 2px 20px;}
	.content h4 {font:bold 14px "Trebuchet MS"; color:#602600; padding:7px 0px 2px 15px;}
	.content h5 {font:bold 12px "Trebuchet MS"; color:#602600; padding:5px 0px 2px 10px;}
	.content h6 {font:bold 10px Verdana; color:#602600; padding:5px 0px 2px 0px;}
	.content h2.pagetitle {position:absolute; top:0px; right:30px; padding:0px; font-size:12px;}
	.post {padding:10px 10px 24px 10px; background: url(http://www.webpagedesign.ws/aspire/post-devider.jpg) bottom no-repeat;}
	* html .post {position:relative; background: url(http://www.webpagedesign.ws/aspire/post-devider.jpg) bottom no-repeat;}
	.content .title {padding:0px;}
	.content .date {font:normal 24px/47px Georgia; margin-right:10px; color:#ffffff; float:left; width:59px; height:56px; overflow:hidden; text-align:center; background: url(http://www.webpagedesign.ws/aspire/date-bg.gif) no-repeat;}
	.content .date .month {font: 14px/16px Arial; color:#4c2604; margin:-10px 0px 0 0; text-transform:lowercase;}
	.content h1 a, .content h1 a:hover {color:#602600; text-decoration:none;}
	.content p.author {color:#240f02; padding:0px 0px 0px 0px; font-size:11px;}
	.entry {position:relative; padding:0 0 10px 0; clear:both;}
	.entry img {border:1px solid #99ba09; margin:3px 5px; max-width:603px}
	.postmetadata {padding:5px 75px 0px 20px; text-align:right; background: url(http://www.webpagedesign.ws/aspire/num-comm-right.jpg) 100% 5px no-repeat; margin-right:15px; clear:both;}
	* html .postmetadata {display:inline-block;}
	*:first-child+html .postmetadata {display:inline-block;}
	.postmetadata .comm-num-left {padding:5px 0px 7px 75px; float:right; background: url(http://www.webpagedesign.ws/aspire/num-comm-left.jpg) no-repeat;}

	.content h2.center {padding:25px 0; text-align:center;}
	.navigation {position:absolute; left:10px; bottom:-22px; z-index:300; font-size:11px;}
	.navigation a, .navigation a:link, .navigation a:active  {float:left; font-size:11px; background:#ca9417 url(http://www.webpagedesign.ws/aspire/page-num-bg.gif) 0 0 no-repeat; line-height:16px; padding:0 4px; color:#602600; margin:0 3px 0 0; border:none;}
	.navigation a:hover {background:#602600 url(http://www.webpagedesign.ws/aspire/page-num-bg.gif) 0 0 no-repeat; color:#ca9417; text-decoration:none;}

#main ul {position:relative; list-style:none; padding:5px 20px;}
#main ul li {display:block; padding:2px 0px 2px 12px;  background: url(http://www.webpagedesign.ws/aspire/marker.gif) 0px 7px no-repeat;}
#main ol {padding: 5px 40px; list-style: decimal}
#main ol li {padding:2px 0px 2px 0px;}


#comments {}
#comments a {}
#comments h4 {padding-left:20px;}
.nocomments {padding: 0 20px 30px 20px;}
.comment-top {position:relative; background: url(http://www.webpagedesign.ws/aspire/comment-top.jpg) center top no-repeat; padding-top:10px;}
.comment-bottom {position:relative; background: url(http://www.webpagedesign.ws/aspire/comment-bottom.jpg) center bottom no-repeat;}
	.message-by {padding:15px 0 5px 0; font:16px/18px "Trebushet MS"; color:#602600; text-align:center;}
	.message-count {text-align:center;}
	.message-count span {display:inline-block; border:1px solid #8a5f3b; font:12px/14px Georgia; position:relative; padding:0 5px;}
	.message-count span b.count-l {position:absolute; left:-74px; top:1px; height:14px; width:72px; line-height:0px; font-size:0px; background: url(http://www.webpagedesign.ws/aspire/message-number-right.gif) left top no-repeat;}
	.message-count span b.count-r {position:absolute; right:-76px; top:1px; height:14px; width:74px; line-height:0px; font-size:0px; background: url(http://www.webpagedesign.ws/aspire/message-number-left.gif) right top no-repeat;}
	.message-entry {position:relative; padding:10px 20px 20px 20px;}
		.message-time {font-size:11px; line-height:20px; color:#efe7c6; height:20px; width:250px; background: #b27110 url(http://www.webpagedesign.ws/aspire/message-time-right.gif) right top no-repeat; margin:10px 20px 0 10px;}
		.message-time span {display:block; height:20px; padding:0 25px; background: url(http://www.webpagedesign.ws/aspire/message-time-left.gif) left top no-repeat;}


#response {position:relative;}
#response h4 {padding:20px 0px 5px 20px;}
#response div.form {width:100%; position:relative; border:1px solid #a4813c;}
* html #response div.form {width:100%;}
#response div.form #commentform {padding:10px;}

	.inputs {position:relative; width:49%; float:left;}
		.input {position:relative;}
		.input b {color:#c97e00;}
		.inputs input {position:relative; background:#ede5c3; border:1px solid #a4813c; width:99%; padding:2px; margin-bottom:5px;}
	.message {position:relative; width:49%; float:right; text-align:center;}
	.message .input {margin-bottom:0px; text-align:center;}
	.message textarea {background:#ede5c3; border:1px solid #a4813c; width:99%; height:92px; padding:1px;}
	.submit {text-align:right; margin-top:10px;}
	* html .submit {margin-top:0px;}
	*:first-child+html .submit {margin-top:0px;}



#sidebars {position:relative; width:350px; float:right; margin-top:-66px;}
#sidebars #searchform #s {border:1px solid #212121; background:#689330; background-image:none; color:#ffffff; width:100%; height:auto !important; margin:0px 0 0 0px;}
#sidebar-left {width:170px; float:left; overflow:hidden;}
#sidebar-right {width:170px; float:right; overflow:hidden;}

#sidebars .widget {background:url(http://www.webpagedesign.ws/aspire/sidebartop.jpg) center top no-repeat; margin-top:15px; padding-top:30px}
#sidebars .widget-content {background:url(http://www.webpagedesign.ws/aspire/sidebarbottom.jpg) center bottom no-repeat;padding:0px 10px 15px 10px;}
#sidebars .widget h2 {position:relative; font:bold 16px "Trebuchet MS"; color:#602600; margin:0px; text-align:center; background:url(http://www.webpagedesign.ws/aspire/sidebarh2.jpg) center bottom no-repeat; padding:0px 10px 18px 10px;}

#sidebars a {color:#602600;}
#sidebars ul {display:inline-block; position:relative; padding:3px 0 0px 0; list-style:none; background:none}
#sidebars ul li {display:block; position:relative; font-size: 12px; color:#240f02; padding:0px 0px}
* html #sidebars ul li {display:inline-block;}
*:first-child+html #sidebars ul li {display:inline-block;}
#sidebars ul li a {color:#602600; padding:2px 0px 2px 15px; display:block; background: url(http://www.webpagedesign.ws/aspire/sb-marker.gif) 3px 7px no-repeat;}
#sidebars ul li.current-cat a {color:#240f02; background:#c18c35 url(http://www.webpagedesign.ws/aspire/sb-marker-hover.gif) 3px 7px no-repeat;}
#sidebars ul li a:hover {color:#240f02; background:#c18c35 url(http://www.webpagedesign.ws/aspire/sb-marker-hover.gif) 3px 7px no-repeat; text-decoration:none;}
#sidebars ul li p a {color:#602600; display:inline; background: none; padding:0px;}
#sidebars ul li p a:hover {color:#602600; display:inline; background:#c18c35 none; padding:0px;}
#sidebars ul li ul {padding:0px 0 0px 0px; list-style:none;}
#sidebars ul li ul li a {padding:2px 0px 2px 25px; background: url(http://www.webpagedesign.ws/aspire/sb-marker.gif) 13px 7px no-repeat;}
#sidebars ul li ul li a:hover {background:#c18c35 url(http://www.webpagedesign.ws/aspire/sb-marker-hover.gif) 13px 7px no-repeat;}

#recentcomments li a {background:none !important; padding:0 0 0 0;}
.textwidget iframe {position:relative; margin:0 -5px 10px -5px;}

.logo-bottom {position:absolute; right:30px; bottom:15px; z-index:1000;}

a:hover abbr {border:none;}


#footer {width:990px; margin:0 auto; text-align:left;}
#footer a {color:#602600;}
.copy {position:relative; padding:25px 0px 15px 0px; font-size:11px; z-index:100; width:590px; text-align:right;}
.valid {position:absolute; right:-200px; top:22px; font-size:11px; background:#ca9417 url(http://www.webpagedesign.ws/aspire/page-num-bg.gif) 0 0 no-repeat; line-height:22px; padding:0 7px;}

.ping-track {position:relative; border:1px solid #a4813c; padding:10px;}

.up {text-transform:uppercase;}
.center {text-align:center;}
.l, .left {float:left;}
.r, .right {float:right;}
.textleft {text-align:left !important;}
.clear {clear:both;}

div.script:
var timestamp = "";
if (timestamp != '') {
	var timesplit = timestamp.split(",");
	var date_yyyy = timesplit[2];
	var timesplit = timesplit[1].split(" ");
	var date_dd = timesplit[2];
	var date_mmm = timesplit[1].substring(0, 3);
}

b:includable.script:
    (function() {
      var items = ;
      var msgs = ;
      var config = ;

// 
      var cursor = null;
      if (items && items.length > 0) {
        cursor = parseInt(items[items.length - 1].timestamp) + 1;
      }

      var bodyFromEntry = function(entry) {
        var text = (entry &&
                    ((entry.content && entry.content.$t) ||
                     (entry.summary && entry.summary.$t))) ||
            '';
        if (entry && entry.gd$extendedProperty) {
          for (var k in entry.gd$extendedProperty) {
            if (entry.gd$extendedProperty[k].name == 'blogger.contentRemoved') {
              return '<span class="deleted-comment">' + text + '</span>';
            }
          }
        }
        return text;
      }

      var parse = function(data) {
        cursor = null;
        var comments = [];
        if (data && data.feed && data.feed.entry) {
          for (var i = 0, entry; entry = data.feed.entry[i]; i++) {
            var comment = {};
            // comment ID, parsed out of the original id format
            var id = /blog-(\d+).post-(\d+)/.exec(entry.id.$t);
            comment.id = id ? id[2] : null;
            comment.body = bodyFromEntry(entry);
            comment.timestamp = Date.parse(entry.published.$t) + '';
            if (entry.author && entry.author.constructor === Array) {
              var auth = entry.author[0];
              if (auth) {
                comment.author = {
                  name: (auth.name ? auth.name.$t : undefined),
                  profileUrl: (auth.uri ? auth.uri.$t : undefined),
                  avatarUrl: (auth.gd$image ? auth.gd$image.src : undefined)
                };
              }
            }
            if (entry.link) {
              if (entry.link[2]) {
                comment.link = comment.permalink = entry.link[2].href;
              }
              if (entry.link[3]) {
                var pid = /.*comments\/default\/(\d+)\?.*/.exec(entry.link[3].href);
                if (pid && pid[1]) {
                  comment.parentId = pid[1];
                }
              }
            }
            comment.deleteclass = 'item-control blog-admin';
            if (entry.gd$extendedProperty) {
              for (var k in entry.gd$extendedProperty) {
                if (entry.gd$extendedProperty[k].name == 'blogger.itemClass') {
                  comment.deleteclass += ' ' + entry.gd$extendedProperty[k].value;
                } else if (entry.gd$extendedProperty[k].name == 'blogger.displayTime') {
                  comment.displayTime = entry.gd$extendedProperty[k].value;
                }
              }
            }
            comments.push(comment);
          }
        }
        return comments;
      };

      var paginator = function(callback) {
        if (hasMore()) {
          var url = config.feed + '?alt=json&v=2&orderby=published&reverse=false&max-results=50';
          if (cursor) {
            url += '&published-min=' + new Date(cursor).toISOString();
          }
          window.bloggercomments = function(data) {
            var parsed = parse(data);
            cursor = parsed.length < 50 ? null
                : parseInt(parsed[parsed.length - 1].timestamp) + 1
            callback(parsed);
            window.bloggercomments = null;
          }
          url += '&callback=bloggercomments';
          var script = document.createElement('script');
          script.type = 'text/javascript';
          script.src = url;
          document.getElementsByTagName('head')[0].appendChild(script);
        }
      };
      var hasMore = function() {
        return !!cursor;
      };
      var getMeta = function(key, comment) {
        if ('iswriter' == key) {
          var matches = !!comment.author
              && comment.author.name == config.authorName
              && comment.author.profileUrl == config.authorUrl;
          return matches ? 'true' : '';
        } else if ('deletelink' == key) {
          return config.baseUri + '/comment/delete/'
               + config.blogId + '/' + comment.id;
        } else if ('deleteclass' == key) {
          return comment.deleteclass;
        }
        return '';
      };

      var replybox = null;
      var replyUrlParts = null;
      var replyParent = undefined;

      var onReply = function(commentId, domId) {
        if (replybox == null) {
          // lazily cache replybox, and adjust to suit this style:
          replybox = document.getElementById('comment-editor');
          if (replybox != null) {
            replybox.height = '250px';
            replybox.style.display = 'block';
            replyUrlParts = replybox.src.split('#');
          }
        }
        if (replybox && (commentId !== replyParent)) {
          replybox.src = '';
          document.getElementById(domId).insertBefore(replybox, null);
          replybox.src = replyUrlParts[0]
              + (commentId ? '&parentID=' + commentId : '')
              + '#' + replyUrlParts[1];
          replyParent = commentId;
        }
      };

      var hash = (window.location.hash || '#').substring(1);
      var startThread, targetComment;
      if (/^comment-form_/.test(hash)) {
        startThread = hash.substring('comment-form_'.length);
      } else if (/^c[0-9]+$/.test(hash)) {
        targetComment = hash.substring(1);
      }

      // Configure commenting API:
      var configJso = {
        'maxDepth': config.maxThreadDepth
      };
      var provider = {
        'id': config.postId,
        'data': items,
        'loadNext': paginator,
        'hasMore': hasMore,
        'getMeta': getMeta,
        'onReply': onReply,
        'rendered': true,
        'initComment': targetComment,
        'initReplyThread': startThread,
        'config': configJso,
        'messages': msgs
      };

      var render = function() {
        if (window.goog && window.goog.comments) {
          var holder = document.getElementById('comment-holder');
          window.goog.comments.render(holder, provider);
        }
      };

      // render now, or queue to render when library loads:
      if (window.goog && window.goog.comments) {
        render();
      } else {
        window.goog = window.goog || {};
        window.goog.comments = window.goog.comments || {};
        window.goog.comments.loadQueue = window.goog.comments.loadQueue || [];
        window.goog.comments.loadQueue.push(render);
      }
    })();
//
